/**
 * @summary List visit requests for an organization
 */
export const getListVisitRequestsUrl = (
  orgId: string,
  params?: ListVisitRequestsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/organizations/${orgId}/visit-requests?${stringifiedParams}`
    : `/api/organizations/${orgId}/visit-requests`;
};

export const listVisitRequests = async (
  orgId: string,
  params?: ListVisitRequestsParams,
  options?: RequestInit,
): Promise<PaginatedVisitRequests> => {
  return customFetch<PaginatedVisitRequests>(
    getListVisitRequestsUrl(orgId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getListVisitRequestsQueryKey = (
  orgId: string,
  params?: ListVisitRequestsParams,
) => {
  return [
    `/api/organizations/${orgId}/visit-requests`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListVisitRequestsQueryOptions = <
  TData = Awaited<ReturnType<typeof listVisitRequests>>,
  TError = ErrorType<unknown>,
>(
  orgId: string,
  params?: ListVisitRequestsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listVisitRequests>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListVisitRequestsQueryKey(orgId, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listVisitRequests>>
  > = ({ signal }) =>
    listVisitRequests(orgId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!orgId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listVisitRequests>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListVisitRequestsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listVisitRequests>>
>;
export type ListVisitRequestsQueryError = ErrorType<unknown>;

