/**
 * @summary Get visit request by ID
 */
export const getGetVisitRequestUrl = (orgId: string, requestId: string) => {
  return `/api/organizations/${orgId}/visit-requests/${requestId}`;
};

export const getVisitRequest = async (
  orgId: string,
  requestId: string,
  options?: RequestInit,
): Promise<VisitRequest> => {
  return customFetch<VisitRequest>(getGetVisitRequestUrl(orgId, requestId), {
    ...options,
    method: "GET",
  });
};

export const getGetVisitRequestQueryKey = (
  orgId: string,
  requestId: string,
) => {
  return [`/api/organizations/${orgId}/visit-requests/${requestId}`] as const;
};

export const getGetVisitRequestQueryOptions = <
  TData = Awaited<ReturnType<typeof getVisitRequest>>,
  TError = ErrorType<unknown>,
>(
  orgId: string,
  requestId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getVisitRequest>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetVisitRequestQueryKey(orgId, requestId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getVisitRequest>>> = ({
    signal,
  }) => getVisitRequest(orgId, requestId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!(orgId && requestId),
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getVisitRequest>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

